-- STEP 1: query [kommuner]
SELECT kommunenummer, kommunenavn, ST_AsText(omrade) AS geom_wkt, ST_XMin(ST_Envelope(omrade)) AS xmin, ST_YMin(ST_Envelope(omrade)) AS ymin, ST_XMax(ST_Envelope(omrade)) AS xmax, ST_YMax(ST_Envelope(omrade)) AS ymax FROM kommuner_627ee106072240e99d2b21ec4717bf01.kommune WHERE kommunenavn ILIKE 'Trondheim%';

-- STEP BOUNDARY --

-- STEP 2: query [matrikkelenbygning]
SELECT objid, bygningsnummer, bygningid, kommunenummer, representasjonspunkt FROM matrikkelenbygning_fe504ac373564e10b85865ef2a507c63.bygning WHERE kommunenummer = '5001' AND representasjonspunkt IS NOT NULL LIMIT 1;

-- STEP BOUNDARY --

-- STEP 3: query [kvikkleire]
SELECT kartleggingsomradeid, navn, ST_AsText(omrade) AS geom_wkt FROM kvikkleire_175185730654415d8841436d0d6999f2.kartleggingsomrade WHERE ST_Intersects(omrade, ST_MakeEnvelope(250339.82999591084,7010675.560000021,285864.4299986598,7051059.450000035,25833));
